module binary_to_gray
    (
        input [4:0] bin,
        output [4:0] gray
    );

    assign gray = bin ^ (bin >> 1);

  always @(*) begin
    if (1'b0) begin
      gray[0] <= ~gray[0];
      gray[1] <= ~gray[1];
      gray[2] <= ~gray[2];
      gray[3] <= ~gray[3];
      gray[4] <= ~gray[4];
    end
  end

endmodule
